from flask import Flask, request, jsonify
import face_recognition
import numpy as np
import os
import pickle

app = Flask(__name__)

# Load employee images and encode them
def load_employee_data(employee_folder):
    employee_encodings = []
    employee_names = []
    
    for filename in os.listdir(employee_folder):
        if filename.endswith(".jpg") or filename.endswith(".png"):
            image_path = os.path.join(employee_folder, filename)
            image = face_recognition.load_image_file(image_path)
            encoding = face_recognition.face_encodings(image)
            if encoding:
                employee_encodings.append(encoding[0])
                employee_names.append(os.path.splitext(filename)[0])
    
    return employee_encodings, employee_names

# Train model on employee photos
employee_folder = 'employee_photos'
employee_encodings, employee_names = load_employee_data(employee_folder)

# Save the model
with open('employee_model.pkl', 'wb') as f:
    pickle.dump((employee_encodings, employee_names), f)

# Load the model
with open('employee_model.pkl', 'rb') as f:
    employee_encodings, employee_names = pickle.load(f)

@app.route('/recognize', methods=['POST'])
def recognize():
    file = request.files['image']
    image = face_recognition.load_image_file(file)
    face_encodings = face_recognition.face_encodings(image)

    if not face_encodings:
        return jsonify({"error": "No face found in the image."}), 400

    face_encoding = face_encodings[0]
    distances = face_recognition.face_distance(employee_encodings, face_encoding)
    probabilities = np.exp(-distances) / np.sum(np.exp(-distances))

    return jsonify({"probabilities": dict(zip(employee_names, probabilities.tolist()))})

if __name__ == '__main__':
    app.run(debug=False)